updates.replacement:
extra_context_object
    : '{}'
    | '{' "project_name" ':' '"Overwritten Project"' '}'
    | '{' "use_docker" ':' '"true"' '}'
    // nested dictionary for deep‑merge
    | '{' "project_name" ':' '{' "sub" ':' '"value"' '}' '}'
    // list value for deep‑merge of list variables
    | '{' "license" ':' '[' '"MIT"' ',' '"GPL"' ']' '}'
    // boolean‑style strings for prompt conversion
    | '{' "use_docker" ':' '"yes"' '}'
    | '{' "use_docker" ':' '"no"' '}'
    ;

hooks_object
    : '{' "pre_prompt" ':' hook_script ',' "pre_gen_project" ':' hook_script ',' "post_gen_project" ':' hook_script '}'
    // all hooks null (no hooks)
    | '{' "pre_prompt" ':' 'null' ',' "pre_gen_project" ':' 'null' ',' "post_gen_project" ':' 'null' '}'
    // successful hook scripts
    | '{' "pre_prompt" ':' hook_script ',' "pre_gen_project" ':' hook_script ',' "post_gen_project" ':' hook_script '}'
    // failing hook: pre_gen_project raises exception after pre_prompt succeeds
    | '{' "pre_prompt" ':' hook_script ',' "pre_gen_project" ':' '"raise SystemExit(1)\\n"' ',' "post_gen_project" ':' 'null' '}'
    ;

nested_templates_value
    : 'null'
    | '[' nested_template_entry ',' nested_template_entry ']'
    // single element list to trigger processing loop
    | '[' nested_template_entry ']'
    ;
